// Parse Claude's response and expose clean fields for the Notion node.
const item = $input.first().json;

// Anthropic returns { content: [{ type: 'text', text: '...' }], ... }
const rawText = item?.content?.[0]?.text ?? '';

// Extract JSON by finding the first { and last } — ignores whatever Claude wraps around it
const start = rawText.indexOf('{');
const end = rawText.lastIndexOf('}');

if (start === -1 || end === -1) {
  throw new Error(`Could not find JSON object in Claude response. Raw: ${rawText}`);
}

const cleaned = rawText.slice(start, end + 1);

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error(`Claude did not return valid JSON. Raw: ${rawText}`);
}

// Validate format — fall back to 'carousel' if Claude ever drifts
const allowedFormats = ['carousel', 'reel', 'blog post'];
const format = allowedFormats.includes(parsed.format) ? parsed.format : 'carousel';

// Validate topic tag — fall back to 'automation' if Claude ever drifts
const allowedTags = ['ai-tools', 'automation', 'notion', 'n8n', 'content-strategy', 'build-in-public', 'hot-take', 'workflow', 'prompt-engineering', 'client-work'];
const topic_tag = allowedTags.includes(parsed.topic_tag) ? parsed.topic_tag : 'automation';

// Safely pull hooks — default to empty objects if Claude returns fewer than 3
const hooks = Array.isArray(parsed.hooks) ? parsed.hooks : [];
const h1 = hooks[0] || {};
const h2 = hooks[1] || {};
const h3 = hooks[2] || {};

// Pull the original Telegram message back into scope
const original = $('Telegram Trigger').first().json.message;

return [
  {
    json: {
      format,
      topic_tag,
      hook_1: (h1.hook || '').slice(0, 300),
      draft_1: h1.draft || '',
      angle_1: h1.angle || 'problem',
      hook_2: (h2.hook || '').slice(0, 300),
      draft_2: h2.draft || '',
      angle_2: h2.angle || 'curiosity',
      hook_3: (h3.hook || '').slice(0, 300),
      draft_3: h3.draft || '',
      angle_3: h3.angle || 'contrarian',
      original_text: original.text,
      telegram_chat_id: original.chat.id,
      captured_at: new Date().toISOString()
    }
  }
];

